import { cursor } from './stores/cursor';
import { difficulty } from './stores/difficulty';
import { gamePaused } from './stores/game';
import { grid, userGrid, invalidCells, setStoreEnhancer } from './stores/grid';
import { timer } from './stores/timer';
import { hints } from './stores/hints';
import { enhanceGridStoreWithDomain } from '../../domain/StoreEnhancer.js';
import { get } from 'svelte/store';

// 初始化领域层增强器
const storeEnhancer = enhanceGridStoreWithDomain(userGrid, grid, invalidCells);
setStoreEnhancer(storeEnhancer);

/**
 * Start new game with a generated sudoku
 *
 * @param {('veryeasy' | 'easy' | 'medium' | 'hard')} diff - Difficulty
 */
export function startNew(diff) {
	difficulty.set(diff);
	const initialGrid = (diff => {
		// 获取生成的初始网格
		grid.generate(diff);
		return get(grid);
	})(diff);

	// 初始化领域对象
	storeEnhancer.initializeDomain(initialGrid);

	cursor.reset();
	timer.reset();
	hints.reset();

	location.hash = '';
}

/**
 * Start new game with a custom sudoku
 *
 * @param {string} sencode - Sencode to decode
 */
export function startCustom(sencode) {
	difficulty.setCustom();
	const initialGrid = (() => {
		grid.decodeSencode(sencode);
		return get(grid);
	})();

	// 初始化领域对象
	storeEnhancer.initializeDomain(initialGrid);

	cursor.reset();
	timer.reset();
	hints.reset();
}

/**
 * Pause the game
 */
export function pauseGame() {
	timer.stop();
	gamePaused.set(true);
}

/**
 * Resume (un-pause) the game
 */
export function resumeGame() {
	timer.start();
	gamePaused.set(false);
}

/**
 * 撤销最后一个操作（使用领域对象）
 */
export function undo() {
	storeEnhancer.undo();
}

/**
 * 重做最后一个被撤销的操作（使用领域对象）
 */
export function redo() {
	storeEnhancer.redo();
}

/**
 * 检查是否可以撤销
 */
export function canUndo() {
	return storeEnhancer.canUndo();
}

/**
 * 检查是否可以重做
 */
export function canRedo() {
	return storeEnhancer.canRedo();
}

/**
 * 获取领域对象实例
 */
export function getGameInstance() {
	return storeEnhancer.getGameInstance();
}

export default {
	startNew,
	startCustom,
	pause: pauseGame,
	resume: resumeGame,
	undo,
	redo,
	canUndo,
	canRedo,
	getGameInstance
};